var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아하하… 하하… 진짜 아프다.","JPN":"アハハ……ハハ……本当に痛いです。","ENG":"Ah hah hah… haha... That really hurt.","TWN":"哈、哈……哈哈……好痛喔。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_ELITE_BLASTER_SKILL_START"},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"\xA0너무 강해서, 떨림이 멎지 않을 정도야.","JPN":"\xA0あまりにも強すぎて、震えが止まりません。","ENG":"It's so strong that I can't stop shaking.","TWN":"你很強，強到讓我無法停止顫抖。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만…","JPN":"でも……","ENG":"But...","TWN":"但……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"넌 나랑 싸우느라 힘을 다 써버려서 차원을 뚫고 도망치지 못해.","JPN":"あなたは私と戦うのに力を使い切っちゃって、次元を超えて逃げられませんよ。","ENG":"if you use all your power on me, you won't be able to escape by crossing dimensions.","TWN":"這場戰鬥已經用盡了我們所有的力量，你無法從次元中逃脫了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그 몸집을 움직이려면 엄청난 에너지가 필요하잖아, 그렇지?","JPN":"その体を動かすためには、ものすごいエネルギーが必要でしょう？　違いますか？","ENG":"It takes a lot of energy to move something your size, no?","TWN":"移動這具身體需要很多能量吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하아… 나도 이제 못 놀겠어. 피를 너무 흘려서 힘이 없거든.","JPN":"はあ……もう私も遊べません。出血多量で力が出なくて。","ENG":"*Sigh* I don't think I can continue either. I've lost too much blood and have no strength left.","TWN":"哈……我也到極限了，現在已經沒有力氣了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"자, 열심히 싸운 보상이야. 날 마음대로 해줘.","JPN":"はい、頑張って戦ったご褒美です。私をどうにでもしてください。","ENG":"Here, it's your reward for fighting me with all your might. Do whatever you want with me.","TWN":"來吧，作為和我認真戰鬥的獎勵，就是你可以隨意處置我。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"부숴도 되고, 먹어도 돼.","JPN":"粉々にしてもいいし、食べてもいいですよ。","ENG":"You can destroy me, or even eat me.","TWN":"撕碎我也好，吃掉我也好。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"왜… 갑자기 멈추는 거야?","JPN":"どうして……いきなり辞めるんですか？","ENG":"Why... did it suddenly stop?","TWN":"……為什麼突然停下來了？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"넌 침식체잖아? 사람을 앞에 두고 왜 멀뚱히 서있는 건데?","JPN":"あなたは侵食体でしょう？　私の前で、何ボーっと突っ立ってるんですか？","ENG":"Aren't you a C.O.? How can you just stand there when there's a human right in front of you?","TWN":"你不是侵蝕體嗎？為什麼還傻呆呆地站在這裡？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처는 나랑 약속했어요.","JPN":"ラッチャーはシェパードと約束したよ。","ENG":"It's because Lurcher promised Shepherd.","TWN":"因為牧羊犬和獵犬做了約定。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"싸움은 누가 괴롭힐 때만 하기로.","JPN":"誰かにいじめられた時にだけ戦うって。","ENG":"That he'll fight only when someone is hurting him.","TWN":"只有當別人欺負我們時，才會打架。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"약… 속?","JPN":"約……束？","ENG":"Promised... you?","TWN":"約……定？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐래. 지성도 없는 침식체가 그런 소통을 할 수 있을 리 없잖아.","JPN":"何言ってるんですか。知性もない侵食体が、そんなやり取りできるわけないでしょう？","ENG":"Whatever. There's no way a mindless C.O. can communicate.","TWN":"你在說些什麼？一個沒有智慧的侵蝕體，怎麼可能進行這樣的交流。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처는 혼자 있는 거 무서워하고, 누가 겁주면 싫어해요.","JPN":"ラッチャーは一人でいるのが怖くて、誰かが脅すのが嫌いなの。","ENG":"Lurcher was afraid of being alone, and hates it when someone scares him.","TWN":"獵犬害怕一個人，也不喜歡別人嚇唬它。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처는 도망치는 법을 몰라서, 겁을 주면 달려 들어요.","JPN":"ラッチャーは逃げる方法がわからなくて、誰かが怖がらせると攻撃するの。","ENG":"Lurcher doesn't know how to run away, so he runs toward whatever is scaring it.","TWN":"獵犬也不知道該如何逃跑，所以當你嚇到它的時候，它反而會衝向你。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처는요. 당신보다 또렷한 마음이 있어요.","JPN":"ラッチャーはね。あなたよりはっきりした心を持ってる。","ENG":"Lurcher has a clearer heart than you.","TWN":"比起你，獵犬有一顆更加透徹的心。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에이, 마음이라니 말도 안 돼.","JPN":"そんな、心なんてあり得ません。","ENG":"C'mon, that thing having a heart? No way.","TWN":"蛤？那種東西怎麼會有心呢？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"너희 둘은 심장도, 피도 없는 실험용 기계일 뿐인데?","JPN":"あなたたちは心臓も、血もない実験用の機械でしょう？","ENG":"You two are both heartless, bloodless experimental machines.","TWN":"你們兩個只不過是無血無淚的機械實驗體吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>리액터 코어 폭발까지 남은 예상 시간…/</color>","JPN":"<color=#ff3636>リアクターコアの爆発まで予想残り時間……/</color>","ENG":"<color=#ff3636>Time remaining until Reactor Core meltdown.../</color>","TWN":"<color=#ff3636>預計反應堆爆炸剩餘時間……/</color>"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>3분…/</color>","JPN":"<color=#ff3636>3分……/</color>","ENG":"<color=#ff3636>3 minutes.../</color>","TWN":"<color=#ff3636>3分鐘……/</color>"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L31_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"기계라도 상관없어요.","JPN":"機械でも関係ない。","ENG":"It doesn't matter if we are machines.","TWN":"就算是機器也沒關係。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐하는 거야, 셰퍼드?","JPN":"何のつもりですか？　シェパード。","ENG":"What are you doing, Shepherd?","TWN":"你在做什麼，牧羊犬？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이제 곧 포드가 출발할 건데 그걸 부수고 나와버리면 어떡해?","JPN":"もうすぐポッドが出発するのに、壊して出てきちゃダメでしょう？","ENG":"The pod's going to leave soon, but why did you break out of it?","TWN":"打碎了分離艙……你不想回家了嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그건 스펜서가 널 살리려고 양보한 자리잖아! 잊은 거야?!","JPN":"それはスペンサーがあなたを助けるために譲った席でしょう？　忘れちゃったんですか！？","ENG":"Spencer gave you that pod so you could live! Or did you forget that already?!","TWN":"這是史賓瑟為了救你而放棄的位置！你忘了嗎？！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"상관없어요.","JPN":"いいの。","ENG":"It doesn't matter.","TWN":"沒關係。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드는 명령권자의 명령도 따르지 않아요.","JPN":"シェパードは命令権者の命令にも従わないの。","ENG":"Shepherd will not listen to Shepherd's commander.","TWN":"牧羊犬不會聽指揮官的命令了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"약속도 안 지켜요.","JPN":"約束も守らない。","ENG":"Nor will Shepherd keep promises.","TWN":"也不要遵守約定了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"내가 아끼는 사람을 지키기 위해, 스스로 결정해요.","JPN":"シェパードが大切に思ってる人を守るために、自分で決める。","ENG":"Shepherd will make Shepherd's own decisions, to protect the person Shepherd cherishes.","TWN":"牧羊犬會自己做決定，為了保護在乎牧羊犬的人。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐?","JPN":"何ですって？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처. 여기서 나가고 싶지?","JPN":"ラッチャー。ここから出たいんだよね？","ENG":"Lurcher, you want to leave this place, don't you?","TWN":"獵犬也想離開這裡吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드가 집에 가려고 했던 에너지. 전부 너한테 줄게.","JPN":"シェパードがおウチに帰るのに必要なエネルギー。全部あなたにあげる。","ENG":"The energy Shepherd was supposed to use to go home. Shepherd will give it to you.","TWN":"來，牧羊犬把回家的能量全部都給你。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그러니까, 부탁 하나만 들어줘.","JPN":"だから、お願いしてもいい？","ENG":"In return, do Shepherd one favor.","TWN":"作為回報，請幫牧羊犬一個忙。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DINO_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DINO_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_05"},{"id":"L1_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"우와, 러처가 다시 회복했잖아?","JPN":"うわっ、ラッチャーが回復しましたね。","ENG":"Whoa, Lurcher just recovered.","TWN":"哇，獵犬又恢復了？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"셰퍼드… 사는 걸 포기하면서까지 날 죽이고 싶었던 거니?","JPN":"シェパード……生きることを諦めてまで、私を殺したかったのですか？","ENG":"Shepherd... did you want to kill me that much? Enough to even give up on living?","TWN":"牧羊犬…你不會是為了殺我，連活命都不想要了吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"죽지 않아요.","JPN":"死なない。","ENG":"No one will die.","TWN":"不會死的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"아무도.","JPN":"誰も。","ENG":"No one.","TWN":"誰都不會死。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"차원균열…? 러처가 가진 그림자 핵으로 만든 건가?","JPN":"次元亀裂……？　ラッチャーが持っているシャドウの核で作ったんですか？","ENG":"A dimensional rift...? Did Lurcher make it with its core?","TWN":"次元裂縫……？這是獵犬用暗影核心創造的嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_03"},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"차원균열로 도망칠 셈이야?","JPN":"次元亀裂に逃げるつもりですか？","ENG":"Are you going to flee through the rift?","TWN":"你打算透過次元裂縫逃跑？這就是你的計畫了？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"도망치지 않아요.","JPN":"逃げない。","ENG":"Shepherd won't run away.","TWN":"牧羊犬不會逃跑。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"도망이 아니면 뭣하러…","JPN":"逃げないなら、どうして……","ENG":"If not, then–","TWN":"不逃跑？打算做什麼？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이 균열의 규모는 설마…? 여길 전부 날려버리릴 작정이야?","JPN":"この亀裂の規模は、まさか……？　ここを丸ごと飛ばすつもりですか？","ENG":"The scale of the rift... Are you thinking of transferring this whole space?","TWN":"這種規模的裂縫……你該不會是打算炸掉整個地方吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"위험해! 그림자의 차원이동은 전혀 안정적이지 않아!","JPN":"危険です！　シャドウの次元移動は、全然安定していません！","ENG":"That's dangerous! A Shadow's dimensional jump is unstable!","TWN":"這太危險了！暗影的次元移動根本不穩定！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"운 나쁘면 우리 전부 허수차원으로 튕겨나갈 수도 있다고!","JPN":"運が悪ければ、私たちはみんな虚数次元に弾き飛ばされるかもしれないですよ！","ENG":"If we're unlucky, we're all going to end up in the imaginary space!","TWN":"如果運氣不好的話，我們都有可能被扔進虛空次元的！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"네가 그렇게 되면 돌아가신 프리하트 박사님께서 기뻐할 것 같아?","JPN":"そうなれば、亡くなったプラハト博士が喜ぶと思いますか？","ENG":"Do you think that's what the late Dr. Freeheart wanted for you?","TWN":"已故的普立哈特博士知道你這麼做，也會不高興的！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"셰퍼드는 소중한 사람을 지켜요.","JPN":"シェパードは大切な人を守る。","ENG":"Shepherd protects the person Shepherd cherishes.","TWN":"牧羊犬，要保護在乎牧羊犬的人。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그게 명령보다 더 중요한…","JPN":"それが命令より重要な……","ENG":"What's more important than any order is...","TWN":"這比命令更重要……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"내 의지에요.","JPN":"シェパードの気持ち。","ENG":"Shepherd's will.","TWN":"這是牧羊犬的意志。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아하하… 뭐야 그게.","JPN":"アハハ……なんですか、それ。","ENG":"Ah hah hah... You can't be serious.","TWN":"哈哈……什麼啊。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"나보다 말이 안 통하는 꼬마네.","JPN":"私より融通の利かないチビちゃんですね。","ENG":"This kid is even more stubborn than me.","TWN":"這小鬼，比我還難溝通。"},"stage":{"bg":"WHITE","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};